import logo from "./logo.svg";
import "./App.css";
import Typewriter from "typewriter-effect";

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1></h1>

        <Navbar />
      </header>
    </div>
  );
}

export default App;

const Profile = () => {
  return (
    <>
      <div>
        <img src="#" alt="burgeon" className="display-pic" />
        <h1>
          Hello <span>Am Burgeon</span>
        </h1>
        {}
      </div>
    </>
  );
};
const Navbar = () => {};

import React, { useState, useEffect } from "react";

const typewriter = ({ texts, typingSpeed = 150, delay = 1000 }) => {
  const [currentText, setCurrentText] = useState("");
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isTyping, setIsTyping] = useState(true);

  useEffect(() => {
    let timeout;
    if (isTyping) {
      // Typing logic
      if (currentText.length < texts[currentIndex].length) {
        timeout = setTimeout(() => {
          setCurrentText(texts[currentIndex].slice(0, currentText.length + 1));
        }, typingSpeed);
      } else {
        // Switch to "waiting" after typing is complete
        setIsTyping(false);
        timeout = setTimeout(() => {
          setIsTyping(true);
          setCurrentText("");
          setCurrentIndex((currentIndex + 1) % texts.length); // Loop through texts
        }, delay);
      }
    }
    return () => clearTimeout(timeout);
  }, [currentText, isTyping, currentIndex, texts, typingSpeed, delay]);

  return <div>{currentText}</div>;
};
